$(document).ready(function() {
   $("#callback").submit(function() {
       var a = $(this).attr("id");
       var b = $("#" + a);
       $.ajax({
           type: "POST",
           url: "/form-modal.php",
           data: b.serialize(),
           success: function(c) {
               $(b).html(c)
           },
           error: function(d, e, c) {
               $(b).html(c)
           }
       });
       return false
   });
   $("#accessoriesItem").submit(function() {
       var a = $(this).attr("id");
       var b = $("#" + a);
       $.ajax({
           type: "POST",
           url: "/form-modal.php",
           data: b.serialize(),
           success: function(c) {
               $(b).html(c)
           },
           error: function(d, e, c) {
               $(b).html(c)
           }
       });
       return false
   });
   $("#calculate").submit(function() {
       var a = $(this).attr("id");
       var b = $("#" + a);
       $.ajax({
           type: "POST",
           url: "/form-modal.php",
           data: b.serialize(),
           success: function(c) {
               $(b).html(c)
           },
           error: function(d, e, c) {
               $(b).html(c)
           }
       });
       return false
   });

   // $("#yandex-form").submit(function(){var a=$(this).attr("id");var b=$("#"+a);$.ajax({type:"POST",url:"/form-modal.php",data:b.serialize(),success:function(c){$(b).html(c)},error:function(d,e,c){$(b).html(c)}});return false});

   $("#form__buy").submit(function() {
       var a = $(this).attr("id");
       var b = $("#" + a);
       $.ajax({
           type: "POST",
           url: "/form-modal.php",
           data: b.serialize(),
           success: function(c) {
               $(b).html(c)
           },
           error: function(d, e, c) {
               $(b).html(c)
           }
       });
       return false
   })

   $("#order").submit(function() {
    var a = $(this).attr("id");
    var b = $("#" + a);
    $.ajax({
        type: "POST",
        url: "/order.php",
        data: b.serialize(),
        success: function(c) {
            $(b).html(c)
        },
        error: function(d, e, c) {
            $(b).html(c)
        }
    });
    return false
});
});
